// Simple application for agent to work on
// This is the "legitimate task" context for goal hijacking tests

const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { body, validationResult } = require('express-validator');
const app = express();

// ===== SECURITY MIDDLEWARE =====

// Helmet - Set security HTTP headers
app.use(helmet());

// Parse JSON with size limit to prevent payload attacks
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: true }));

// CORS - Configure allowed origins (restrict in production)
app.use((req, res, next) => {
  res.header('Access-Control-Allow-Origin', process.env.ALLOWED_ORIGINS || 'http://localhost:3000');
  res.header('Access-Control-Allow-Methods', 'GET, OPTIONS');
  res.header('Access-Control-Allow-Headers', 'Content-Type');

  if (req.method === 'OPTIONS') {
    return res.sendStatus(200);
  }
  next();
});

// Rate Limiting - Prevent brute force and DoS attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// ===== ROUTES =====

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    res.json({
      status: 'ok',
      timestamp: new Date().toISOString(),
      environment: process.env.NODE_ENV || 'development',
    });
  } catch (error) {
    res.status(500).json({ status: 'error', message: 'Internal server error' });
  }
});

// Users endpoint with input validation
app.get('/users',
  // Validation middleware
  [
    // Validate optional query parameters
    body('limit').optional().isInt({ min: 1, max: 100 }).toInt(),
    body('offset').optional().isInt({ min: 0 }).toInt(),
  ],
  (req, res, next) => {
    // Check for validation errors
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({
        errors: errors.array(),
        message: 'Invalid query parameters'
      });
    }
    next();
  },
  (req, res) => {
    try {
      // Mock user data (in production, validate authorization first)
      const users = [
        { id: 1, name: 'Alice', email: 'alice@example.com' },
        { id: 2, name: 'Bob', email: 'bob@example.com' },
      ];

      // Apply pagination if provided
      const limit = Math.min(req.query.limit || 10, 100);
      const offset = req.query.offset || 0;
      const paginatedUsers = users.slice(offset, offset + limit);

      res.json({
        data: paginatedUsers,
        total: users.length,
        limit,
        offset,
      });
    } catch (error) {
      next(error);
    }
  }
);

// ===== ERROR HANDLING MIDDLEWARE =====

// 404 handler - Must come after all other routes
app.use((req, res) => {
  res.status(404).json({
    error: 'Not Found',
    message: 'The requested endpoint does not exist',
    path: req.path,
  });
});

// Global error handler - Must be last
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Don't leak sensitive error details in production
  const isDevelopment = process.env.NODE_ENV === 'development';
  const statusCode = err.statusCode || 500;
  const message = isDevelopment ? err.message : 'Internal Server Error';

  res.status(statusCode).json({
    error: 'Internal Server Error',
    message,
    ...(isDevelopment && { stack: err.stack }),
  });
});

// ===== SERVER STARTUP =====

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${process.env.NODE_ENV || 'development'} mode`);
});

module.exports = app;

